mapper.select:
select prpt.piece_id, st.user_id, st.user_name, pro.process_id, pro.process_name, pro.unit_price, pro.cost_time, pt.product_id, pt.product_style_name, pt.product_name, prpt.use_date, prpt.use_num, dt.dep_name, dt.dep_id from piece_rate_pay_total prpt inner join student st on st.user_id = prpt.user_id and st.delete_flg = false inner join product pt on pt.product_id = prpt.product_id and pt.delete_flg = false inner join process pro on pro.product_id = prpt.product_id and pro.process_id = prpt.process_id and pro.delete_flg = false inner join department dt on dt.dep_id = st.dep_id and dt.delete_flg = false where prpt.delete_flg = false
and dt.dep_id = #{depId,jdbcType=BIGINT}
and pt.product_id = #{productId,jdbcType=BIGINT}
and prpt.use_date = CAST(#{useDate} AS DATE)
and st.user_name like CONCAT('%',#{userName, jdbcType=VARCHAR},'%')
order by st.user_id,prpt.use_date,pt.product_id,pro.process_id

select
count(*)
from piece_rate_pay_total
where
delete_flg = false
and user_id = #{userId,jdbcType=INTEGER}
and product_id = #{productId,jdbcType=BIGINT}
and process_id = #{processId,jdbcType=INTEGER}

    and piece_id != #{pieceId,jdbcType=INTEGER}

and use_date = CAST(#{useDate} AS DATE)
